21	/// The number of shards per sharded lock. Must be a power of two.
22	const NUM_SHARDS: usize = 8;
23	
24	/// A shard containing a single reader-writer lock.
25	struct Shard {
26	    /// The inner reader-writer lock.
27	    lock: RwLock<()>,
28	
29	    /// The write-guard keeping this shard locked.
30	    ///
31	    /// Write operations will lock each shard and store the guard here. These guards get dropped at
32	    /// the same time the big guard is dropped.
33	    write_guard: UnsafeCell<Option<RwLockWriteGuard<'static, ()>>>,
34	}
35	
36	/// A sharded reader-writer lock.
37	///
38	/// This lock is equivalent to [`RwLock`], except read operations are faster and write operations
39	/// are slower.
40	///
41	/// A `ShardedLock` is internally made of a list of *shards*, each being a [`RwLock`] occupying a
42	/// single cache line. Read operations will pick one of the shards depending on the current thread
43	/// and lock it. Write operations need to lock all shards in succession.
44	///
45	/// By splitting the lock into shards, concurrent read operations will in most cases choose
46	/// different shards and thus update different cache lines, which is good for scalability. However,
47	/// write operations need to do more work and are therefore slower than usual.
48	///
49	/// The priority policy of the lock is dependent on the underlying operating system's
50	/// implementation, and this type does not guarantee that any particular policy will be used.
51	///
52	/// # Poisoning
53	///
54	/// A `ShardedLock`, like [`RwLock`], will become poisoned on a panic. Note that it may only be
55	/// poisoned if a panic occurs while a write operation is in progress. If a panic occurs in any
56	/// read operation, the lock will not be poisoned.
57	///
58	/// # Examples
59	///
60	/// ```
61	/// use crossbeam_utils::sync::ShardedLock;
62	///
63	/// let lock = ShardedLock::new(5);
64	///
65	/// // Any number of read locks can be held at once.
66	/// {
67	///     let r1 = lock.read().unwrap();
68	///     let r2 = lock.read().unwrap();
69	///     assert_eq!(*r1, 5);
70	///     assert_eq!(*r2, 5);
71	/// } // Read locks are dropped at this point.
72	///
73	/// // However, only one write lock may be held.
74	/// {
75	///     let mut w = lock.write().unwrap();
76	///     *w += 1;
77	///     assert_eq!(*w, 6);
78	/// } // Write lock is dropped here.
79	/// ```
80	///
81	/// [`RwLock`]: std::sync::RwLock
82	pub struct ShardedLock<T: ?Sized> {
83	    /// A list of locks protecting the internal data.
84	    shards: Box<[CachePadded<Shard>]>,
85	
86	    /// The internal data.
87	    value: UnsafeCell<T>,
88	}
89	
90	unsafe impl<T: ?Sized + Send> Send for ShardedLock<T> {}
91	unsafe impl<T: ?Sized + Send + Sync> Sync for ShardedLock<T> {}
92	
93	impl<T: ?Sized> UnwindSafe for ShardedLock<T> {}
94	impl<T: ?Sized> RefUnwindSafe for ShardedLock<T> {}
